+            10,
+            "agent-mail",
+            "host-z",
+            7777,
+        )]);
+
+        let mut engine = DiscoveryEngine::new(DiscoveryConfig::default());
+        let _ = engine.poll(20, &mut [&mut first_pass_a, &mut first_pass_b]);
+        assert_eq!(engine.snapshot().len(), 2);
