+        let mut bridge = StaticDiscoverySource::new(vec![InstanceSighting {
+            source: DiscoverySignalKind::Heartbeat,
+            observed_at_ms: 30,
+            project_key_hint: Some("agent-mail".to_owned()),
+            host_name: Some("host-z".to_owned()),
